/* ═══════════════════════════════════════════════════════════════
   LandingPage.tsx
   ═══════════════════════════════════════════════════════════════ */
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useProjects } from '../context/ProjectsContext';

export default function LandingPage() {
  const navigate = useNavigate();
  const { createNewProject } = useProjects();

  function handleStart() {
    const project = createNewProject();
    navigate(`/projects/${project.id}`);
  }

  function CloudMonHeroSVG() {
  return (
    <div className="w-full max-w-4xl mx-auto rounded-3xl overflow-hidden bg-white border border-slate-200 shadow-2xl">
      <svg
        viewBox="0 0 800 500"
        xmlns="http://www.w3.org/2000/svg"
        className="w-full h-auto"
      >
        <defs>
          <radialGradient id="mesh-grad" cx="20%" cy="20%" r="80%">
            <stop offset="0%" stopColor="#F8FAFC" />
            <stop offset="100%" stopColor="#FFFFFF" />
          </radialGradient>

          <filter id="soft-shadow" x="-20%" y="-20%" width="150%" height="150%">
            <feDropShadow dx="0" dy="10" stdDeviation="15" floodColor="#64748B" floodOpacity="0.1" />
          </filter>

          <style>
            {`
              @keyframes dash { to { stroke-dashoffset: -20; } }
              @keyframes float { 
                0%, 100% { transform: translateY(0px); } 
                50% { transform: translateY(-8px); } 
              }
              @keyframes pulse-red {
                0% { opacity: 1; }
                50% { opacity: 0.3; }
                100% { opacity: 1; }
              }
              @keyframes scale-in {
                from { transform: scale(0.8); opacity: 0; }
                to { transform: scale(1); opacity: 1; }
              }
              .flow-line { stroke-dasharray: 5, 5; animation: dash 1s linear infinite; }
              .floating { animation: float 5s ease-in-out infinite; }
              .removing { animation: pulse-red 2s ease-in-out infinite; }
              .adding { animation: scale-in 0.8s ease-out forwards; }
              .stagger-1 { animation-delay: 0.2s; }
              .stagger-2 { animation-delay: 0.4s; }
            `}
          </style>
        </defs>

        {/* Background Canvas */}
        <rect width="800" height="500" fill="url(#mesh-grad)" />

        {/* Network Grid Overlay */}
        <g opacity="0.05" stroke="#64748B" strokeWidth="1">
          {Array.from({ length: 10 }).map((_, i) => (
            <line key={`v-${i}`} x1={i * 80} y1="0" x2={i * 80} y2="500" />
          ))}
          {Array.from({ length: 6 }).map((_, i) => (
            <line key={`h-${i}`} x1="0" y1={i * 80} x2="800" y2={i * 80} />
          ))}
        </g>

        {/* =========================================
            INFRASTRUCTURE CANVAS (Left/Center)
            ========================================= */}

        {/* Network Connections */}
        <g fill="none" strokeWidth="2">
          {/* Main Internet Ingress */}
          <path d="M 50 250 L 120 250" stroke="#CBD5E1" strokeWidth="2" />
          <circle cx="50" cy="250" r="4" fill="#3B82F6" />

          {/* Internal Mesh */}
          <path d="M 220 250 Q 280 250 320 180" stroke="#E2E8F0" />
          <path d="M 220 250 Q 280 250 320 320" stroke="#E2E8F0" />

          {/* The "Active" Request Path */}
          <path d="M 220 250 Q 280 250 320 180 L 480 180" stroke="#10B981" strokeWidth="3" className="flow-line" />
        </g>

        {/* Components */}
        <g transform="translate(120, 210)" className="floating">
          {/* Load Balancer */}
          <rect width="100" height="80" rx="12" fill="white" filter="url(#soft-shadow)" stroke="#E2E8F0" />
          <text x="50" y="35" fill="#1E293B" fontSize="10" fontWeight="bold" textAnchor="middle">LB_PRIMARY</text>
          <g transform="translate(25, 45)">
            <rect width="50" height="4" rx="2" fill="#F1F5F9" />
            <rect width="30" height="4" rx="2" fill="#3B82F6" />
            <rect y="10" width="50" height="4" rx="2" fill="#F1F5F9" />
            <rect y="10" width="40" height="4" rx="2" fill="#3B82F6" />
          </g>
        </g>

        {/* OLD SERVER (Being Removed) */}
        <g transform="translate(320, 280)" className="removing">
          <rect width="120" height="90" rx="12" fill="#FEF2F2" stroke="#EF4444" strokeWidth="2" strokeDasharray="4 4" />
          <text x="60" y="30" fill="#991B1B" fontSize="10" fontWeight="bold" textAnchor="middle">LEGACY_VM</text>
          <path d="M45 45 L75 75 M75 45 L45 75" stroke="#EF4444" strokeWidth="2" />
          <text x="60" y="82" fill="#EF4444" fontSize="9" fontWeight="800" textAnchor="middle">REMOVING</text>
        </g>

        {/* NEW SERVERLESS (Being Added) */}
        <g transform="translate(320, 135)" className="adding">
          <rect width="120" height="90" rx="12" fill="#F0FDF4" stroke="#10B981" strokeWidth="2" filter="url(#soft-shadow)" />
          <text x="60" y="30" fill="#166534" fontSize="10" fontWeight="bold" textAnchor="middle">FUNC_HANDLER</text>
          {/* Abstract Code/Scale Graphic */}
          <g transform="translate(35, 45)">
             <rect width="20" height="20" rx="4" fill="#BBF7D0" />
             <rect x="30" width="20" height="20" rx="4" fill="#BBF7D0" />
             <rect y="12" x="15" width="20" height="20" rx="4" fill="#10B981" />
          </g>
          <text x="60" y="82" fill="#10B981" fontSize="9" fontWeight="800" textAnchor="middle">SCALING UP</text>
        </g>

        {/* Database Clusters */}
        <g transform="translate(520, 200)" className="floating" style={{ animationDelay: '-2s' }}>
          <path d="M0 20 Q 50 0 100 20 L 100 80 Q 50 100 0 80 Z" fill="white" filter="url(#soft-shadow)" stroke="#E2E8F0" />
          <path d="M0 20 Q 50 40 100 20" fill="none" stroke="#E2E8F0" />
          <text x="50" y="60" fill="#64748B" fontSize="10" fontWeight="bold" textAnchor="middle">DB_CLUSTER</text>
          <circle cx="50" cy="75" r="3" fill="#10B981" className="pulse-dot" />
        </g>

        {/* =========================================
            COST ANALYSIS PANEL (Right Side)
            ========================================= */}
        <g transform="translate(560, 60)" filter="url(#soft-shadow)">
          <rect width="210" height="380" rx="24" fill="white" fillOpacity="0.98" stroke="#F1F5F9" />

          <g fontFamily="system-ui, sans-serif">
            <text x="24" y="40" fill="#0F172A" fontSize="15" fontWeight="800">Live Optimization</text>
            <text x="24" y="60" fill="#64748B" fontSize="11">Architecture Delta: +1 Function</text>

            {/* Savings Alert */}
            <rect x="24" y="80" width="162" height="36" rx="10" fill="#F0FDF4" />
            <text x="40" y="102" fill="#166534" fontSize="11" fontWeight="700">Estimated Savings: 32%</text>

            {/* Provider Breakdown */}
            <g transform="translate(24, 140)">
              <text y="0" fill="#94A3B8" fontSize="10" fontWeight="bold">AWS TOTAL</text>
              <text x="162" y="0" fill="#0F172A" fontSize="14" fontWeight="800" textAnchor="end">$142.00</text>
              <rect y="12" width="162" height="6" rx="3" fill="#F1F5F9" />
              <rect y="12" width="100" height="6" rx="3" fill="#F59E0B" />
            </g>

            <g transform="translate(24, 200)">
              <text y="0" fill="#94A3B8" fontSize="10" fontWeight="bold">AZURE TOTAL</text>
              <text x="162" y="0" fill="#0F172A" fontSize="14" fontWeight="800" textAnchor="end">$165.50</text>
              <rect y="12" width="162" height="6" rx="3" fill="#F1F5F9" />
              <rect y="12" width="130" height="6" rx="3" fill="#3B82F6" />
            </g>

            <g transform="translate(24, 260)">
              <text y="0" fill="#94A3B8" fontSize="10" fontWeight="bold">GCP TOTAL</text>
              <text x="162" y="0" fill="#10B981" fontSize="14" fontWeight="800" textAnchor="end">$128.90</text>
              <rect y="12" width="162" height="6" rx="3" fill="#F1F5F9" />
              <rect y="12" width="85" height="6" rx="3" fill="#10B981" />
            </g>

            {/* Micro-comparison table */}
            <g transform="translate(24, 310)">
               <rect width="162" height="45" rx="12" fill="#F8FAFC" />
               <text x="15" y="20" fill="#64748B" fontSize="9" fontWeight="bold">COMPUTE UNIT COST</text>
               <text x="15" y="35" fill="#475569" fontSize="10">VM: $0.12/hr</text>
               <text x="90" y="35" fill="#10B981" fontSize="10" fontWeight="bold">FUNC: $0.0004</text>
            </g>
          </g>
        </g>

        {/* UI Elements */}
        <g transform="translate(40, 400)">
           <rect width="140" height="40" rx="10" fill="white" filter="url(#soft-shadow)" stroke="#E2E8F0" />
           <circle cx="25" cy="20" r="10" fill="#3B82F6" opacity="0.1" />
           <text x="45" y="24" fill="#475569" fontSize="10" fontWeight="bold">Request-by-Request</text>
        </g>

      </svg>
    </div> ); 
    }

  return (
    <div className="page landing">
      <div className="hero">
        <div className="hero-copy">
          <span className="hero-kicker">CloudMon</span>
          <h1>Visualize your architecture and see what your decisions actually mean in practise.</h1>
          <p>
            Build a base architecture first, then create request flows as nested files.
            Compare AWS, GCP and Azure costs side-by-side as you design.
          </p>
          <div className="hero-actions">
            <button className="btn-primary" onClick={handleStart}>
              Create a project
            </button>
            <button className="btn-secondary" onClick={() => navigate('/projects')}>
              Browse projects
            </button>
          </div>
        </div>
        <div className="hero-panel">
          {/*<div className="panel-card">
            <h3>Architecture first</h3>
            <p>Sketch components and their connections without extra data detail.</p>
          </div>
          <div className="panel-card">
            <h3>Request-by-request</h3>
            <p>
              Every request starts from your base architecture. Evolve flows
              request-by-request.
            </p>
          </div>
          <div className="panel-card">
            <h3>Cloud cost comparison</h3>
            <p>See AWS, GCP and Azure costs side-by-side in the analysis panel.</p>
          </div>
        </div>*/}
      </div>
      <CloudMonHeroSVG />
    </div>
    </div>

  );
}
